import{_ as t,o as i,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"22. Incidental And Peripheral Duties","description":"","frontmatter":{"title":"22. Incidental And Peripheral Duties","eba":"Doctors in Training 2022-2026","topics":["employment"]},"headers":[],"relativePath":"ebas/doctors-in-training/doctor-employment/22-incidental-and-peripheral-duties.md","filePath":"ebas/doctors-in-training/doctor-employment/22-incidental-and-peripheral-duties.md"}'),n={name:"ebas/doctors-in-training/doctor-employment/22-incidental-and-peripheral-duties.md"};function o(s,e,c,l,d,p){return i(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_22-incidental-and-peripheral-duties" tabindex="-1">22. Incidental And Peripheral Duties <a class="header-anchor" href="#_22-incidental-and-peripheral-duties" aria-label="Permalink to &quot;22. Incidental And Peripheral Duties&quot;">​</a></h1><p><strong>22.1</strong> The Health Service may direct a Doctor to carry out such duties as are within the limits of the Doctor’s skill, competence and training consistent with the classification structure of the Agreement, provided that such duties are not designed to promote de-skilling.</p><p><strong>22.2</strong> The Health Service must not require a Doctor to carry out duties that are outside the limits of the Doctor’s skill, competence and training (including the required level of supervision) consistent with the classification structure of the Agreement</p><p><strong>22.3</strong> Where a Doctor believes a Health Service is requiring them to carry out duties that breach subclause 22.2, the Doctor should</p><p><strong>(a)</strong> where the matter is urgent, escalate via the local Clinical Escalation Pathway; and</p><p><strong>(b)</strong> if not resolved, escalate via the Dispute Resolution Clause.</p><p>Plain language terms: duties, scope of work.</p>',7)])])}const m=t(n,[["render",o]]);export{u as __pageData,m as default};
